INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (11, 10, 1, 72, 1, 1, 0, 0, "だからわたし、\n勇気を出して言ってみたんです！\nお友だちになりませんか、って。", 72021, 0);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (91, 0, 0, 72, 0, "", "", "", "", 72022, "");
