INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (11, 10, 1, 82, 1, 1, 0, 0, "と、不退転の決意を申し上げたら、\nミサト様、「は～い♪」と、\n二つ返事で分かってくださって。", 82025, 0);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (91, 0, 0, 82, 0, "", "", "", "", 82026, "");
