INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (11, 10, 1, 112, 1, 1, 0, 0, "ミツキさんの出してくれた\nオリジナルのお茶、\n不思議な香りでした。", 112012, 0);
