INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (11, 10, 1, 142, 1, 1, 0, 0, "……でも。\n今回の冒険で、夢見ることは\n大きな力だと知りましたから。", 142024, 0);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (91, 0, 0, 142, 0, "", "", "", "", 142025, "");
